    private init() {}
    
    func authenticateUser(completion: @escaping (Bool, String?) -> Void) {
        let context = LAContext()
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            completion(false, "Biometric authentication not available")
            return
        }
        
        let reason = "Authenticate to access your account"
        
        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, 
                              localizedReason: reason,
                              reply: { [weak self] success, authenticationError in
            DispatchQueue.main.async {
                if success {
                    self?.storeAuthenticationStatus(isAuthenticated: true)
                    completion(true, nil)
                } else {
                    let errorMessage = self?.handleAuthenticationError(authenticationError)
                    completion(false, errorMessage)
                }
            }
        })
    }
    
    func checkAuthenticationStatus() -> Bool {
        guard let storedAuth = UserDefaults.standard.object(forKey: "isAuthenticated") as? Bool else {
            return false
        }
        return storedAuth
    }
    
    func clearAuthenticationStatus() {
        UserDefaults.standard.removeObject(forKey: "isAuthenticated")
    }
    
    private func storeAuthenticationStatus(isAuthenticated: Bool) {
        UserDefaults.standard.set(isAuthenticated, forKey: "isAuthenticated")
        UserDefaults.standard.synchronize()
    }
    
    private func handleAuthenticationError(_ error: Error?) -> String {
        guard let error = error as? LAError else {
            return "Authentication failed"
        }
        
        switch error.code {
        case .userCancel:
            return "Authentication cancelled"
        case .userFallback:
            return "Fallback authentication requested"
        case .systemCancel:
            return "System cancelled authentication"
        case .biometryNotAvailable:
            return "Biometric authentication not available"
        case .biometryNotEnrolled:
            return "No biometrics enrolled"
        case .biometryLockout:
            return "Biometric lockout"
        default:
            return "Authentication failed"
        }
    }
